/* ============================================================
   SYSTEL — SONS EMBARQUÉS BASE64 WAV (v3)
   Zéro dépendance fichier externe, zéro 404
   ============================================================ */
const SOUND_BIP = 'data:audio/wav;base64,';
const SOUND_ACQ = 'data:audio/wav;base64,';

let _bipNode = null;

function playBip(loop) {
  stopBip();
  try {
    _bipNode = new Audio(SOUND_BIP);
    _bipNode.loop = !!loop;
    _bipNode.volume = 1.0;
    const p = _bipNode.play();
    if (p) p.catch(() => {
      // Autoplay bloqué — on réessaie sur interaction utilisateur
      document.addEventListener('click', () => { if(_bipNode) _bipNode.play().catch(()=>{}); }, {once:true});
    });
  } catch(e) { console.warn('playBip error', e); }
}

function stopBip() {
  if (_bipNode) {
    try { _bipNode.pause(); _bipNode.currentTime = 0; } catch(e) {}
    _bipNode = null;
  }
}

function playAck() {
  stopBip();
  try {
    const a = new Audio(SOUND_ACQ);
    a.volume = 1.0;
    a.play().catch(() => {});
  } catch(e) { console.warn('playAck error', e); }
}
